1	import { useCallback, useEffect, useMemo, useState } from 'react';
2	import {
3	  ActivityIndicator,
4	  Linking,
5	  Pressable,
6	  SafeAreaView,
7	  ScrollView,
8	  StyleSheet,
9	  Text,
10	  View,
11	} from 'react-native';
12	import { router, useLocalSearchParams } from 'expo-router';
13	import { Check, ChevronLeft, ExternalLink, X } from 'lucide-react-native';
14	import { ButtonPrimary } from '@/components/primitives/Button';
15	import { StatusPill } from '@/components/primitives/StatusPill';
16	import { useToast } from '@/components/primitives/Toast';
17	import { colors, radii, shadows, spacing } from '@/design/tokens';
