378	function SampleVideoCell({ video }: { video: SampleVideoRow }) {
379	  const label = platformLabel(video.platform);
380	  const onPress = useCallback(() => {
381	    void Linking.openURL(video.url).catch(() => {
382	      // Swallowed intentionally — the link may not resolve in the
383	      // simulator (no TikTok/Instagram app installed). There is no
384	      // actionable retry; the URL is the primary info for the creator.
385	    });
386	  }, [video.url]);
387	  return (
388	    <Pressable
389	      onPress={onPress}
390	      style={[styles.sampleRow, shadows.hard]}
391	      accessibilityRole="link"
392	      accessibilityLabel={`Open ${label} sample${video.caption ? `: ${video.caption}` : ''}`}
393	      testID={`listing-sample-${video.sort_order}`}
394	    >
395	      <View style={styles.sampleText}>
396	        <Text style={[textStyles.body, { color: colors.ink }]}>
397	          {video.caption ?? `${label} sample`}
398	        </Text>
399	        <Text style={[textStyles.caption, { color: colors.ink70 }]} numberOfLines={1}>
400	          {video.url}
401	        </Text>
402	      </View>
403	      <ExternalLink color={colors.ink} size={20} strokeWidth={2.5} />
404	    </Pressable>
405	  );
406	}
