408	function EligibilityRow({
409	  condition,
410	  failure,
411	}: {
412	  condition: ConditionRow;
413	  failure: FailedCondition | null;
414	}) {
415	  const passed = failure === null;
416	  const label = eligibilityRowLabel(condition);
417	  const statusColor = passed ? colors.success : colors.danger;
418	  const Icon = passed ? Check : X;
419	  const detail = passed
420	    ? requiredLabel(condition)
421	    : failureDetailLabel(condition, failure);
422	  return (
423	    <View
424	      style={styles.eligibilityRow}
425	      accessible
426	      accessibilityLabel={
427	        passed
428	          ? `${label} passes. Required ${requiredLabel(condition)}.`
429	          : `${label} fails. ${detail}.`
430	      }
431	      testID={`listing-eligibility-${condition.metric}-${condition.platform ?? 'none'}`}
432	    >
433	      <View style={[styles.eligibilityIcon, { borderColor: statusColor }]}>
434	        <Icon color={statusColor} size={16} strokeWidth={3} />
435	      </View>
436	      <View style={styles.eligibilityTextWrap}>
437	        <Text style={[textStyles.body, { color: colors.ink }]}>{label}</Text>
438	        <Text style={[textStyles.caption, { color: colors.ink70 }]}>{detail}</Text>
439	      </View>
440	    </View>
441	  );
442	}
