459	function getInactiveBanner(status: ListingStatus): string | null {
460	  switch (status) {
461	    case 'paused':
462	      return 'This campaign is paused. The lister is reviewing pending applications.';
463	    case 'closed':
464	      return 'This campaign is closed and no longer accepting applications.';
465	    default:
466	      return null;
467	  }
468	}
