470	function eligibilityRowLabel(c: ConditionRow): string {
471	  const platform = c.platform ? platformLabel(c.platform) : '';
472	  const base = metricLabel(c.metric);
473	  return platform ? `${platform} · ${base}` : base;
474	}
475	
476	function metricLabel(metric: string): string {
477	  switch (metric) {
478	    case 'min_followers':
479	      return 'Minimum followers';
480	    case 'min_avg_views_last_n':
481	      return 'Avg views (last 10)';
482	    case 'min_total_likes':
483	      return 'Total likes';
484	    case 'min_videos_posted':
485	      return 'Videos posted';
486	    case 'verified_only':
487	      return 'Verified account';
488	    default:
489	      return metric;
490	  }
491	}
492	
493	function requiredLabel(c: ConditionRow): string {
494	  if (c.operator === 'bool') {
495	    return `Requires ${c.bool_threshold ? 'yes' : 'no'}`;
496	  }
497	  const threshold = c.numeric_threshold;
498	  if (threshold !== null && threshold !== undefined) {
499	    return `Requires ${formatCount(Number(threshold))}+`;
500	  }
501	  return '—';
502	}
503	
504	function failureDetailLabel(
505	  c: ConditionRow,
506	  f: FailedCondition,
507	): string {
508	  const required = requiredLabel(c);
509	  if (typeof f.actual === 'number') {
510	    return `${required} — you have ${formatCount(f.actual)}`;
511	  }
512	  if (typeof f.actual === 'boolean') {
513	    return `${required} — you are ${f.actual ? 'verified' : 'not verified'}`;
514	  }
515	  return `${required} — no data yet`;
516	}
517	
518	function postConditionLabel(c: ConditionRow): string {
519	  switch (c.metric) {
520	    case 'post_family_friendly':
521	      return c.bool_threshold ? 'Family-friendly content only.' : 'Content may be mature.';
522	    case 'post_must_mention':
523	      return c.text_threshold
524	        ? `Must mention ${c.text_threshold}.`
525	        : 'Must include a specific mention.';
526	    case 'post_must_tag_account':
527	      return c.text_threshold
528	        ? `Must tag @${c.text_threshold.replace(/^@/, '')}.`
529	        : 'Must tag the lister account.';
530	    case 'post_min_video_duration_sec':
531	      return c.numeric_threshold !== null
532	        ? `Video at least ${c.numeric_threshold}s.`
533	        : 'Minimum video duration.';
534	    case 'post_max_video_duration_sec':
535	      return c.numeric_threshold !== null
536	        ? `Video at most ${c.numeric_threshold}s.`
537	        : 'Maximum video duration.';
538	    case 'post_min_video_count':
539	      return c.numeric_threshold !== null
540	        ? `Post at least ${c.numeric_threshold} videos.`
541	        : 'Minimum video count.';
542	    default:
543	      return c.metric;
544	  }
545	}
546	
547	function platformLabel(p: Platform): string {
548	  return p === 'tiktok' ? 'TikTok' : 'Instagram';
549	}
550	
551	function formatPrice(priceCents: number, currency: string): string {
552	  const amount = (priceCents / 100).toLocaleString('en-US', {
553	    minimumFractionDigits: 0,
554	    maximumFractionDigits: 2,
555	  });
556	  const code = currency.toUpperCase();
557	  if (code === 'USD') return `$${amount}`;
558	  return `${amount} ${code}`;
559	}
560	
561	function formatCount(n: number): string {
562	  if (n < 1000) return String(n);
563	  if (n < 1_000_000) return `${(n / 1000).toFixed(n < 10_000 ? 1 : 0)}k`;
564	  if (n < 1_000_000_000) return `${(n / 1_000_000).toFixed(n < 10_000_000 ? 1 : 0)}m`;
565	  return `${(n / 1_000_000_000).toFixed(n < 10_000_000_000 ? 1 : 0)}b`;
566	}
